import{_ as t,o as a,c as s,a2 as n}from"./chunks/framework.lVAEw_NY.js";const g=JSON.parse('{"title":"Command line interface","description":"Learn how to use @elenajs/cli to interactively scaffold Elena components with JS, TS, or single-file HTML output.","frontmatter":{"title":"Command line interface","description":"Learn how to use @elenajs/cli to interactively scaffold Elena components with JS, TS, or single-file HTML output."},"headers":[],"relativePath":"advanced/cli.md","filePath":"advanced/cli.md","lastUpdated":1773833331000}'),i={name:"advanced/cli.md"};function o(d,e,l,r,p,c){return a(),s("div",null,[...e[0]||(e[0]=[n(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /elena/advanced/cli.md for this page in Markdown format</div><h1 id="command-line-interface" tabindex="-1">Command line interface <a class="header-anchor" href="#command-line-interface" aria-label="Permalink to &quot;Command line interface&quot;">​</a></h1><p><code>@elenajs/cli</code> is an interactive command line tool for scaffolding Elena components. It generates JavaScript, TypeScript, or single-file HTML source files and scoped CSS with all Elena <a href="/elena/components/overview">Progressive Web Component</a> patterns pre-configured.</p><h2 id="install" tabindex="-1">Install <a class="header-anchor" href="#install" aria-label="Permalink to &quot;Install&quot;">​</a></h2><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-q4vCV" id="tab-OSV2M6R" checked><label data-title="npm" for="tab-OSV2M6R">npm</label><input type="radio" name="group-q4vCV" id="tab-IFdsEgt"><label data-title="yarn" for="tab-IFdsEgt">yarn</label><input type="radio" name="group-q4vCV" id="tab-x3xHZ3y"><label data-title="pnpm" for="tab-x3xHZ3y">pnpm</label></div><div class="blocks"><div class="language-sh vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --save-dev</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @elenajs/cli</span></span></code></pre></div><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yarn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --dev</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @elenajs/cli</span></span></code></pre></div><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --save-dev</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @elenajs/cli</span></span></code></pre></div></div></div><h2 id="usage" tabindex="-1">Usage <a class="header-anchor" href="#usage" aria-label="Permalink to &quot;Usage&quot;">​</a></h2><h3 id="interactive-mode" tabindex="-1">Interactive mode <a class="header-anchor" href="#interactive-mode" aria-label="Permalink to &quot;Interactive mode&quot;">​</a></h3><p>Run without arguments to be guided through all options:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> elena-create</span></span></code></pre></div><h3 id="with-a-component-name" tabindex="-1">With a component name <a class="header-anchor" href="#with-a-component-name" aria-label="Permalink to &quot;With a component name&quot;">​</a></h3><p>Pass a kebab-case name (must contain at least one hyphen) to skip the name prompt:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> elena-create</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-button</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> elena-create</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-stack</span></span></code></pre></div><h2 id="prompts" tabindex="-1">Prompts <a class="header-anchor" href="#prompts" aria-label="Permalink to &quot;Prompts&quot;">​</a></h2><p>The CLI walks you through the following steps:</p><div class="table-container"><table><thead><tr><th>Prompt</th><th>Description</th><th>Default</th></tr></thead><tbody><tr><td><strong>Component name</strong></td><td>Kebab-case name with at least one hyphen (e.g. <code>my-button</code>, <code>my-stack</code>). Skipped if passed as argument.</td><td></td></tr><tr><td><strong>Component features</strong></td><td>Feature toggles for the generated code. See <a href="#component-features">Component features</a> below.</td><td>None selected</td></tr><tr><td><strong>Language</strong></td><td><code>JavaScript</code>, <code>TypeScript</code>, or <code>HTML</code>.</td><td></td></tr><tr><td><strong>Output directory</strong></td><td>Where to generate the component folder.</td><td><code>src/components</code></td></tr></tbody></table></div><h3 id="component-features" tabindex="-1">Component features <a class="header-anchor" href="#component-features" aria-label="Permalink to &quot;Component features&quot;">​</a></h3><p>You can toggle features to include in the generated code:</p><div class="table-container"><table><thead><tr><th>Option</th><th>Description</th></tr></thead><tbody><tr><td><strong>Props</strong></td><td>Adds example props with <code>@attribute</code> / <code>@type</code> JSDoc annotations.</td></tr><tr><td><strong>Events</strong></td><td>Adds <code>events</code> option and <code>@event</code> JSDoc annotations.</td></tr><tr><td><strong>Methods</strong></td><td>Adds an example method stub.</td></tr><tr><td><strong>CSS Variables</strong></td><td>Adds <code>@cssprop</code> JSDoc annotations and CSS custom property declarations.</td></tr><tr><td><strong>CSS Encapsulation</strong></td><td>Adds the <code>all: unset</code> reset to prevent global styles from leaking in.</td></tr><tr><td><strong>CSS SSR Pattern</strong></td><td>Adds <code>:scope:not([hydrated])</code> styles for pre-hydration rendering.</td></tr><tr><td><strong>Code Comments</strong></td><td>Includes JSDoc annotations and CSS comments in the generated code.</td></tr></tbody></table></div><h2 id="generated-files" tabindex="-1">Generated files <a class="header-anchor" href="#generated-files" aria-label="Permalink to &quot;Generated files&quot;">​</a></h2><p>For a component named <code>my-button</code>, the CLI creates:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>src/components/my-button/</span></span>
<span class="line"><span>├── my-button.js (or .ts)</span></span>
<span class="line"><span>└── my-button.css</span></span></code></pre></div><p>When using the HTML language, a single file is generated instead:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>src/components/my-button/</span></span>
<span class="line"><span>└── my-button.html</span></span></code></pre></div>`,23)])])}const m=t(i,[["render",o]]);export{g as __pageData,m as default};
